import React from 'react';
import { Lightbulb } from 'lucide-react';
import DrawerCollapsibleSection from '../DrawerCollapsibleSection';
import AdvisorDetailPanel from './AdvisorDetailPanel';

export default function AdvisorResourceSection({
  recommendations = [],
  indexReady = true,
  isLoading = false,
  currency = 'USD',
}) {
  if (!isLoading && indexReady && !recommendations.length) {
    return null;
  }

  return (
    <DrawerCollapsibleSection
      title="Azure Advisor"
      icon={<Lightbulb size={13} />}
      variant="info"
      defaultOpen={recommendations.length > 0}
      compact
      badge={recommendations.length || null}
      hint="Recommendations from Microsoft Azure Advisor for this resource."
    >
      <AdvisorDetailPanel
        recommendations={recommendations}
        indexReady={indexReady}
        isLoading={isLoading}
        currency={currency}
      />
    </DrawerCollapsibleSection>
  );
}
